INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (165961, 96593, 9, 'ofirgelbart74', 'Both build tension so slowly you almost forget you''re scared until the moment hits — Jaws makes you terrified of water, E.T. makes you cry at a bicycle scene. Spielberg in both films is obsessed with ordinary people feeling something enormous, and both...', NULL);
