INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271095, 159172, 10, 'ofirgelbart74', 'Last Crusade adds Sean Connery as Indy''s father and suddenly the adventure means something personal — the motorcycle chase and the tank battle are great but the moment Henry Sr. says ''I''ve lost him so many times'' is what makes the film unforgettable. R...', NULL);
