INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271095, 256632, 8, 'ofirgelbart74', 'Jack Sparrow is the closest cinema got to creating another Indiana Jones — a hero who seems incompetent and is actually brilliant, and who makes every scene more fun just by being in it. Both films feel like pure adventure that trusts its audience to k...', NULL);
