INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (214755, 61751, 9, 'ofirgelbart74', 'Both are sci-fi films set in futures that feel completely plausible — Minority Report asks what happens when the government punishes you for something you haven''t done yet, Children of Men asks what happens when humanity loses the ability to have child...', NULL);
