INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (1711, 207992, 9, 'ofirgelbart74', 'Both are sci-fi films that use their genre to ask genuinely big philosophical questions — 2001 asks whether we are alone in the universe and what comes after humanity, The Matrix asks whether the world we experience is even real. Both are visually unli...', NULL);
