INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (30959, 210511, 9, 'ofirgelbart74', 'Memento is what Nolan can do when there are no budget constraints on his ideas — the reverse chronology puts you inside Leonard''s amnesia so completely that you feel his frustration and fear. Batman Begins applies the same commitment to psychology to a...', NULL);
